parameters.jsCode:
// Parse Gemini response
const response = $input.first().json;
const textContent = response.candidates?.[0]?.content?.parts?.[0]?.text || '{}';

// Clean up any markdown code blocks
let cleanJson = textContent
  .replace(/```json\n?/g, '')
  .replace(/```\n?/g, '')
  .trim();

try {
  const parsed = JSON.parse(cleanJson);
  return {
    json: {
      selected_topic: parsed.selected_topic || 'Music production trends',
      angle: parsed.angle || 'The industry is changing and most people are sleeping on it',
      content_type: parsed.content_type || 'hot-take',
      urgency: parsed.urgency || 'medium',
      raw_trends: $('Scrape Music Trends').first().json.trends || []
    }
  };
} catch (e) {
  return {
    json: {
      selected_topic: 'Music production trends',
      angle: 'Let me tell you what the industry is really about',
      content_type: 'hot-take',
      urgency: 'medium',
      error: e.message,
      raw_response: cleanJson
    }
  };
}

